const int MAX_LOG = 31;

// dp[p][i]: 从位置 i 开始，跳 2^p 步后到达的位置
vector<vector<int>> dp(n + 1, vector<int>(MAX_LOG));

// 初始化：2^0 = 1 步的情况就是 next 数组本身
for (int i = 1; i <= n; i++) {
    dp[i][0] = next[i];
}

// 预处理：填充整个 dp 表
for (int p = 1; p < MAX_LOG; p++) {
    for (int i = 1; i <= n; i++) {
        // 关键状态转移：
        // 从 i 跳 2^p 步 = 从 i 跳 2^(p-1) 步，再跳 2^(p-1) 步
        dp[i][p] = dp[dp[i][p - 1]][p - 1];
    }
}

// 处理查询
while (q--) {
    int s, k;
    cin >> s >> k;

    int pos = s;
    // 将 k 按二进制分解，从高位到低位或从低位到高位均可
    // 这里采用从低位到高位（即 p 从 0 开始）
    for (int p = 0; p < MAX_LOG; p++) {
        // 如果 k 的二进制表示中第 p 位是 1
        if (k & (1 << p)) {
            pos = dp[pos][p];
        }
    }

    cout << pos << '\n';
}

